from dataclasses import dataclass, field
from typing import Optional

@dataclass
class Task:
    task_id: str
    name: str
    duration_weeks: float
    predecessors: list[str] = field(default_factory=list)  # task_ids that must finish first
    team: str = ""
    # Computed by forward/backward pass:
    earliest_start: float = 0.0
    earliest_finish: float = 0.0
    latest_start: float = 0.0
    latest_finish: float = 0.0

    @property
    def total_float(self) -> float:
        """Weeks of slack before this task hits the critical path."""
        return self.latest_start - self.earliest_start

    @property
    def is_critical(self) -> bool:
        return abs(self.total_float) < 0.001  # float ~= 0

def forward_pass(tasks: list[Task]) -> None:
    """
    Compute ES and EF for all tasks. Tasks must be in topological order
    (no task appears before all its predecessors).
    """
    by_id = {t.task_id: t for t in tasks}
    for task in tasks:
        if not task.predecessors:
            task.earliest_start = 0.0
        else:
            task.earliest_start = max(
                by_id[pred].earliest_finish for pred in task.predecessors
            )
        task.earliest_finish = task.earliest_start + task.duration_weeks

def backward_pass(tasks: list[Task], project_end: float) -> None:
    """
    Compute LS and LF. tasks must be processed in REVERSE topological order.
    project_end is the EF of the last task (from forward pass).
    """
    by_id = {t.task_id: t for t in tasks}
    # Build successor map: task_id → list of tasks that depend on it
    successors: dict[str, list[str]] = {t.task_id: [] for t in tasks}
    for task in tasks:
        for pred in task.predecessors:
            successors[pred].append(task.task_id)

    for task in reversed(tasks):
        succs = successors[task.task_id]
        if not succs:
            task.latest_finish = project_end
        else:
            task.latest_finish = min(by_id[s].latest_start for s in succs)
        task.latest_start = task.latest_finish - task.duration_weeks

def find_critical_path(tasks: list[Task]) -> list[Task]:
    """Return tasks on the critical path, in execution order."""
    critical = [t for t in tasks if t.is_critical]
    return sorted(critical, key=lambda t: t.earliest_start)

from collections import deque, defaultdict

def topological_sort(tasks: list[Task]) -> list[Task]:
    """
    Return tasks in valid execution order. Raises ValueError if there is a cycle.
    """
    in_degree: dict[str, int] = {t.task_id: 0 for t in tasks}
    successors: dict[str, list[str]] = defaultdict(list)
    by_id = {t.task_id: t for t in tasks}

    for task in tasks:
        for pred in task.predecessors:
            successors[pred].append(task.task_id)
            in_degree[task.task_id] += 1

    queue = deque(t.task_id for t in tasks if in_degree[t.task_id] == 0)
    result = []
    while queue:
        tid = queue.popleft()
        result.append(by_id[tid])
        for succ in successors[tid]:
            in_degree[succ] -= 1
            if in_degree[succ] == 0:
                queue.append(succ)

    if len(result) != len(tasks):
        cycle_members = [t.task_id for t in tasks if by_id[t.task_id] not in result]
        raise ValueError(f"Dependency cycle detected among: {cycle_members}")
    return result

def analyse_critical_path(tasks: list[Task]) -> dict:
    sorted_tasks = topological_sort(tasks)
    forward_pass(sorted_tasks)
    project_end = max(t.earliest_finish for t in sorted_tasks)
    backward_pass(sorted_tasks, project_end)
    critical = find_critical_path(sorted_tasks)
    return {
        "project_duration_weeks": project_end,
        "critical_path": [t.task_id for t in critical],
        "critical_path_names": [t.name for t in critical],
        "tasks_by_float": sorted(sorted_tasks, key=lambda t: t.total_float),
    }

@dataclass
class CriticalTaskMonitor:
    task_id: str
    duration_weeks: float
    week_checkpoints: list[int]        # weeks at which to check progress
    expected_progress_at: dict[int, float]  # week → expected % complete

    def evaluate(self, current_week: int, actual_pct: float) -> dict:
        expected = self.expected_progress_at.get(current_week, 0.0)
        gap = expected - actual_pct
        weeks_remaining = self.duration_weeks - current_week
        projected_finish_week = (
            self.duration_weeks / actual_pct if actual_pct > 0 else float("inf")
        )
        return {
            "on_track": gap <= 0.10,
            "gap_pct": round(gap, 2),
            "projected_finish_week": round(projected_finish_week, 1),
            "slip_risk_weeks": max(0, round(projected_finish_week - self.duration_weeks, 1)),
            "escalate": gap > 0.20 or (weeks_remaining <= 1 and actual_pct < 0.80),
        }

def float_consumption_report(tasks: list[Task], current_week: int) -> list[dict]:
    """
    Report tasks where remaining float is less than 2 weeks.
    These are 'near-critical' and require attention.
    """
    near_critical = []
    for task in tasks:
        if task.is_critical:
            continue
        # Remaining float = latest_start - (current_week + 0) assuming not yet started
        remaining_float = task.latest_start - max(current_week, task.earliest_start)
        if remaining_float <= 2:
            near_critical.append({
                "task_id": task.task_id,
                "name": task.name,
                "total_float_weeks": round(task.total_float, 1),
                "remaining_float_weeks": round(remaining_float, 1),
                "latest_safe_start_week": round(task.latest_start, 1),
                "at_risk_of_becoming_critical": remaining_float <= 0,
            })
    return sorted(near_critical, key=lambda x: x["remaining_float_weeks"])

from dataclasses import dataclass
import math

@dataclass
class PERTEstimate:
    name: str
    optimistic: float   # weeks
    most_likely: float
    pessimistic: float

    @property
    def expected(self) -> float:
        return (self.optimistic + 4 * self.most_likely + self.pessimistic) / 6

    @property
    def std_dev(self) -> float:
        return (self.pessimistic - self.optimistic) / 6

    @property
    def variance(self) -> float:
        return self.std_dev ** 2

    def confidence_range(self, z: float = 1.96) -> tuple[float, float]:
        """Return (low, high) at the given z-score (default 95%)."""
        margin = z * self.std_dev
        return (max(0.0, self.expected - margin), self.expected + margin)

    def __str__(self) -> str:
        lo, hi = self.confidence_range()
        return (
            f"{self.name}: E={self.expected:.1f}w  "
            f"σ={self.std_dev:.1f}w  95%=[{lo:.1f}, {hi:.1f}]"
        )


def critical_path_pert(tasks: list[PERTEstimate]) -> dict:
    """
    For a LINEAR critical path (no branching), sum expected durations
    and combine variances to get overall project statistics.
    """
    total_expected = sum(t.expected for t in tasks)
    total_variance = sum(t.variance for t in tasks)
    total_std_dev = math.sqrt(total_variance)
    lo, hi = (
        max(0.0, total_expected - 1.96 * total_std_dev),
        total_expected + 1.96 * total_std_dev,
    )
    return {
        "expected_weeks": round(total_expected, 1),
        "std_dev_weeks": round(total_std_dev, 1),
        "p95_range": (round(lo, 1), round(hi, 1)),
    }


# Example: GenAI model deployment critical path
cp_tasks = [
    PERTEstimate("Data clearance & DPA review",  1, 2,  5),
    PERTEstimate("Model fine-tuning",             2, 4,  8),
    PERTEstimate("Safety evaluation",             1, 2,  4),
    PERTEstimate("Platform integration & testing",2, 3,  6),
    PERTEstimate("Staged rollout",                1, 2,  3),
]

for t in cp_tasks:
    print(t)

summary = critical_path_pert(cp_tasks)
print(f"\nProject total: {summary['expected_weeks']}w  "
      f"± {summary['std_dev_weeks']}w  "
      f"95% = {summary['p95_range']}")
# Project total: 13.0w  ± 2.3w  95% = (8.5, 17.5)

from dataclasses import dataclass, field
from enum import Enum
from typing import Callable

class FloatStatus(Enum):
    HEALTHY      = "healthy"       # > 3w
    WATCH        = "watch"         # 2-3w
    NEAR_CRITICAL= "near_critical" # 1-2w
    CRITICAL     = "critical"      # < 1w
    ON_CP        = "on_critical_path"  # 0 or negative

def classify_float(total_float_weeks: float) -> FloatStatus:
    if total_float_weeks <= 0:
        return FloatStatus.ON_CP
    elif total_float_weeks < 1:
        return FloatStatus.CRITICAL
    elif total_float_weeks < 2:
        return FloatStatus.NEAR_CRITICAL
    elif total_float_weeks <= 3:
        return FloatStatus.WATCH
    else:
        return FloatStatus.HEALTHY


@dataclass
class EscalationRunbook:
    """Defines escalation actions per float status."""
    actions: dict[FloatStatus, list[str]] = field(default_factory=dict)

    def required_actions(self, status: FloatStatus) -> list[str]:
        return self.actions.get(status, [])

    def execute(
        self,
        status: FloatStatus,
        notify: Callable[[str, str], None],   # (channel, message)
    ) -> None:
        for action in self.required_actions(status):
            notify(status.value, action)


STANDARD_RUNBOOK = EscalationRunbook(actions={
    FloatStatus.WATCH: [
        "Add task to programme risk register with 'watch' status",
        "Identify at least one schedule recovery option",
        "Report in next weekly programme update",
    ],
    FloatStatus.NEAR_CRITICAL: [
        "Raise formal risk entry with mitigation plan",
        "Initiate daily check-in with task owner",
        "Brief delivery director within 24 hours",
    ],
    FloatStatus.CRITICAL: [
        "Escalate to programme board immediately",
        "Activate contingency plan if available",
        "Re-forecast delivery date and communicate to stakeholders",
    ],
    FloatStatus.ON_CP: [
        "Convene emergency re-plan session (same day)",
        "Notify CTO and programme sponsor",
        "Freeze scope changes until critical path is recovered",
    ],
})


def evaluate_schedule_health(
    tasks: list[dict],   # each: {"name": str, "float": float}
    runbook: EscalationRunbook,
    notify: Callable[[str, str], None],
) -> list[dict]:
    """Run the float policy across all tasks and trigger runbook actions."""
    report = []
    for task in tasks:
        status = classify_float(task["float"])
        runbook.execute(status, notify)
        report.append({
            "task": task["name"],
            "float_weeks": task["float"],
            "status": status.value,
        })
    return sorted(report, key=lambda r: r["float_weeks"])
